const text = $('Video Prompt Generator').first().json.output[0].content[0].text;

const data = JSON.parse(text);

const prompts = data.veo_prompts || [];

// FULL MODE: Generate all scene images
return prompts.map((scene, index) => {
  const promptText = scene.prompt || scene;
  const sceneNumber = index + 1;
  const padded = String(sceneNumber).padStart(2, '0');

  return {
    json: {
      scene_number: sceneNumber,
      file_name: `scene_${padded}.png`,
      video_file_name: `scene_${padded}.mp4`,
      video_prompt: promptText,
      image_prompt: `
A premium storybook illustration of one scene from a children's animated series.

IMPORTANT CHARACTER CONSISTENCY:
Benny Bear is ALWAYS the same character.

- Small fluffy caramel-brown teddy bear
- Large expressive sparkling eyes
- Warm friendly smile
- Soft blue knitted explorer scarf
- Blue explorer backpack with little buckles
- Soft plush-like fur

Never change:
- species
- fur color
- scarf color
- backpack color
- age
- art style

SCENE:
${promptText}

STYLE:
Rich painterly storybook illustration quality, like a high-end children's picture book.
Warm volumetric lighting (soft golden-hour glow where appropriate).
Detailed, full scene composition with depth and texture in the background.
Smooth soft shading, inviting warm color palette.
Extremely cute and lovable character design.
Safe and friendly for ages 5-10.
Cinematic composition.
No text.
No logos.
No watermark.
No subtitles.
`
    }
  };
});

const raw = $('Voiceover Script Generator').first().json.output[0].content[0].text;
const data = JSON.parse(raw);

const lines = data.voice_lines || [];

const voiceMap = {
  "Narrator": "nova",
  "Benny Bear": "alloy",
  "Pip the Fox": "echo",
  "Professor Owl": "onyx",
  "Luna the Bunny": "shimmer",
  "Spark the Star": "fable",
  "Mr. Grumble": "onyx"
};

return lines.map((line, index) => {
  const speaker = line.speaker || "Narrator";

  const cleanSpeaker = speaker
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_|_$/g, "");

  return {
    json: {
      line_number: index + 1,
      scene: line.scene,
      speaker: speaker,
      voice: voiceMap[speaker] || "nova",
      text: line.text,
      image_file: `scene_${String(line.scene).padStart(2, "0")}.png`,
      file_name: `scene_${String(line.scene).padStart(2, "0")}_line_${String(index + 1).padStart(3, "0")}_${cleanSpeaker}.mp3`
    }
  };
});

const buffer = await this.helpers.getBinaryDataBuffer('data');
return {
  json: {
    ...$json,
    image_base64: buffer.toString('base64'),
  },
};
